const items = $input.all();
const grouped = {};

const getVal = (row, ...options) => {
    const keys = Object.keys(row);
    for (const opt of options) {
        const match = keys.find(k => k.toLowerCase().trim() === opt.toLowerCase().trim());
        if (match) return row[match];
    }
    return null;
};

items.forEach((item, index) => {
    const row = item.json;
    const paidBy = getVal(row, 'Pa name', 'Father name (paid by)', 'Paid by');
    const stdName = getVal(row, 'Std Name', 'Student name');
    const regNo = getVal(row, 'Reg No', 'Reg No(Gr No)');
    const amountRaw = getVal(row, 'Amount sar', 'Amount');
    const paidIn = getVal(row, 'paid in', 'Month');
    const grade = getVal(row, 'Grade');

    if (!paidBy) return;

    if (!grouped[paidBy]) {
        grouped[paidBy] = {
            "Paid by": paidBy,
            "Date": new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }).replace(/ /g, '-'),
            "Month": paidIn || "Current",
            "Receipt No": Math.floor(1000 + Math.random() * 9000),
            "Students": [],
            "Total Amount": 0
        };
    }

    const amount = parseFloat(String(amountRaw || 0).replace(/[^0-9.-]+/g,"")) || 0;
    const particular = `Monthly Fee (${paidIn || 'N/A'}) | Grade: ${grade || 'N/A'}`;

    grouped[paidBy].Students.push({
        "Gr No": regNo || "N/A",
        "Student Name": stdName || "N/A",
        "Particular": particular,
        "Amount": amount
    });

    grouped[paidBy]["Total Amount"] += amount;
});

return Object.keys(grouped).map(key => ({ json: grouped[key] }));

