const finalItems = [];

for (let i = 0; i < items.length; i++) {
    const item = items[i];
    let html = (typeof item.json === 'string') ? item.json : (item.json.data || JSON.stringify(item.json));

    // Get consistent data from the grouping node
    const data = $node["Group Students by Parent"].json;

    if (!data || !data.Students) continue;

    let tableRows = "";
    data.Students.forEach(student => {
        tableRows += `<tr><td>${student["Gr No"]}</td><td>${student["Student Name"]}</td><td>${student["Particular"]}</td><td>SAR ${student["Amount"]}</td></tr>`;
    });

    html = html.replace('{{RECEIPT_NO}}', data["Receipt No"])
               .replace('{{MONTH}}', data["Month"])
               .replace('{{STATUS}}', "Paid")
               .replace('{{PAID_BY}}', data["Paid by"])
               .replace('{{DATE}}', data["Date"])
               .replace('{{TABLE_ROWS}}', tableRows)
               .replace('{{TOTAL_AMOUNT}}', data["Total Amount"]);

    finalItems.push({
        json: {
            "fileName": `Invoice_${data["Paid by"].replace(/\\s+/g, '_')}.pdf`,
            "html_content": html
        }
    });
}

return finalItems;
